import type { IParticleEffectBubbleProps } from '@kyokuya/particle-bubble'
import ParticleEffectBubble from '@kyokuya/particle-bubble'
import { useParticleEffect2D } from '@kyokuya/particle-helper'
import { TrendingFlatOutlined } from '@mui/icons-material'
import { Link } from 'gatsby'
import React, { useRef } from 'react'
import Seo from '@/component/seo'
import classes from './style.module.styl'

const bubbleOptions: IParticleEffectBubbleProps = {}

export default function NotFoundPage(): React.ReactElement {
  const containerRef = useRef<HTMLDivElement>(null)

  // Use particle effect when magic-panel is visible.
  useParticleEffect2D<IParticleEffectBubbleProps>(containerRef, ParticleEffectBubble, bubbleOptions)

  return (
    <div ref={containerRef} className={classes.container}>
      <Seo title="Page Not Found (404)" />
      <div className={classes.content}>
        <div className={classes.contentBanner} />
        <div className={classes.message}>
          <header>
            <h1>404 Not Found</h1>
            <Link to="/">
              Back to Home...
              <TrendingFlatOutlined />
            </Link>
          </header>
        </div>
      </div>
    </div>
  )
}
