import { createBackgroundCanvas, requestAnimationFrame } from './canvas'
import type { IAnimation } from './canvas'

export interface CanvasParticle2DConstructor<T = any> {
  new (container: HTMLElement, options?: T): CanvasParticle2D
}

export abstract class CanvasParticle2D {
  protected readonly container: HTMLElement
  protected readonly canvas: HTMLCanvasElement
  protected readonly context: CanvasRenderingContext2D
  protected running: boolean
  protected timer: number | null

  constructor(container: HTMLElement) {
    this.container = container
    this.canvas = createBackgroundCanvas(container)
    this.context = this.canvas.getContext('2d')!
    this.running = false
    this.timer = null
    window.addEventListener('resize', this._onresize)
  }

  /**
   * Toggle visibility of the canvas.
   * @param visible
   */
  public readonly toggleVisibility = (visible: boolean): void => {
    if (visible) {
      this.canvas.style.display = 'block'
      this.canvas.style.visibility = 'visible'
      this.start()
    } else {
      this.canvas.style.display = 'none'
      this.canvas.style.visibility = 'hidden'
      this.stop()
    }
  }

  /**
   * Start animation.
   */
  public start(): void {
    if (this.running) return
    this.running = true
    this._requestFrame(this._drawAnimation)
  }

  /**
   * Store animation.
   */
  public stop(): void {
    this.running = false
  }

  /**
   * Perform clean operations.
   */
  public destroy(): void {
    // Cancel the timing task.
    if (this.timer != null) {
      cancelAnimationFrame(this.timer)
    }

    // Remove event listeners.
    window.removeEventListener('resize', this._onresize)

    // Unmount canvas.
    this.canvas.parentNode?.removeChild(this.canvas)
  }

  protected abstract draw(): void

  /**
   * Draw the animation contents.
   */
  protected readonly _drawAnimation = (): void => {
    this.draw()
    this._requestFrame(this._drawAnimation)
  }

  /**
   * Request a frame for the animation.
   * @param animation
   */
  protected _requestFrame(animation: IAnimation): void {
    if (this.running) {
      this.timer = requestAnimationFrame(animation)
    }
  }

  /**
   * Reset operation during onresize.
   */
  protected _onresize = (): void => {
    const { canvas, container } = this
    canvas.width = container.clientWidth
    canvas.height = container.clientHeight
  }
}
